svg.script:

function showIt(evt,idElem) {
  var evtElem = evt.target;
  var doc = evtElem.ownerDocument;
  var targetElem = doc.getElementById(idElem);
  if (targetElem) {
    switch(evt.type) {
      case 'mouseover':
        var style = targetElem.style;
        if (style) {
          style.setProperty('fill','red');
        }
        break;
      case 'mouseout' :
        var style = targetElem.style;
        if (style) {
          style.setProperty('fill','blue');
        } 
    } // switch
  } // if
} // function showIt
